import numpy as np

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape

    # Find separator rows and columns
    sep_rows = [r for r in range(H) if all(grid[r, c] == 6 for c in range(W))]
    sep_cols = [c for c in range(W) if all(grid[r, c] == 6 for r in range(H))]

    # Extract panel ranges
    row_ranges = []
    prev = 0
    for sr in sep_rows:
        row_ranges.append((prev, sr))
        prev = sr + 1
    row_ranges.append((prev, H))

    col_ranges = []
    prev = 0
    for sc in sep_cols:
        col_ranges.append((prev, sc))
        prev = sc + 1
    col_ranges.append((prev, W))

    # Extract panels
    panels = {}
    for ri, (r0, r1) in enumerate(row_ranges):
        for ci, (c0, c1) in enumerate(col_ranges):
            panels[(ri, ci)] = grid[r0:r1, c0:c1]

    # Determine chain direction based on edge activity
    has_tb = False
    has_lr = False
    for panel in panels.values():
        ph, pw = panel.shape
        if any(panel[0, c] != 7 for c in range(pw)) or any(panel[-1, c] != 7 for c in range(pw)):
            has_tb = True
        if any(panel[r, 0] != 7 for r in range(ph)) or any(panel[r, -1] != 7 for r in range(ph)):
            has_lr = True

    direction = 'vertical' if has_tb else 'horizontal'

    # Build chain
    if direction == 'vertical':
        entry_exit = {}
        for k, panel in panels.items():
            top_cols = tuple(c for c in range(panel.shape[1]) if panel[0, c] != 7)
            bot_cols = tuple(c for c in range(panel.shape[1]) if panel[-1, c] != 7)
            entry_exit[k] = (top_cols, bot_cols)

        start = [k for k, (e, x) in entry_exit.items() if len(e) == 0][0]
        chain = [start]
        used = {start}
        while len(chain) < len(panels):
            current = chain[-1]
            exit_pos = entry_exit[current][1]
            for k, (e, x) in entry_exit.items():
                if k not in used and e == exit_pos:
                    chain.append(k)
                    used.add(k)
                    break
    else:  # horizontal
        entry_exit = {}
        for k, panel in panels.items():
            left_rows = tuple(r for r in range(panel.shape[0]) if panel[r, 0] != 7)
            right_rows = tuple(r for r in range(panel.shape[0]) if panel[r, -1] != 7)
            entry_exit[k] = (left_rows, right_rows)

        start = [k for k, (e, x) in entry_exit.items() if len(e) == 0][0]
        chain = [start]
        used = {start}
        while len(chain) < len(panels):
            current = chain[-1]
            exit_pos = entry_exit[current][1]
            for k, (e, x) in entry_exit.items():
                if k not in used and e == exit_pos:
                    chain.append(k)
                    used.add(k)
                    break

    # Assemble output
    ordered_panels = [panels[k] for k in chain]
    ph, pw = ordered_panels[0].shape

    if direction == 'vertical':
        # Stack vertically with separator rows
        result_rows = []
        for i, panel in enumerate(ordered_panels):
            if i > 0:
                result_rows.append(np.full((1, pw), 6, dtype=int))
            result_rows.append(panel)
        result = np.vstack(result_rows)
    else:
        # Place horizontally with separator columns
        result_cols = []
        for i, panel in enumerate(ordered_panels):
            if i > 0:
                result_cols.append(np.full((ph, 1), 6, dtype=int))
            result_cols.append(panel)
        result = np.hstack(result_cols)

    return result.tolist()

